import{_ as o,o as n,c as i,ae as a}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Link Appearance (New)","description":"","frontmatter":{"title":"Link Appearance (New)","slug":"link-appearance-new"},"headers":[],"relativePath":"account-hub/link-appearance-new.md","filePath":"account-hub/link-appearance-new.md"}'),t={name:"account-hub/link-appearance-new.md"};function r(l,e,s,d,c,u){return n(),i("div",null,[...e[0]||(e[0]=[a('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This article explains how to configure your link settings in Branch. The <strong>Link Controls</strong> page allows you to manage link domains, customize link appearance, and configure routing rules for different platforms and devices.</p><p>To access these settings, go to <strong>Configuration &gt; Link Controls</strong> in Branch.</p><p>The <strong>Link Controls</strong> page contains two tabs:</p><ul><li><strong>Link Appearance</strong> - Configure your link domains, social media previews, and QR code styling.</li><li><strong>Link Routing Rules</strong> - Configure where users are redirected based on their platform and device.</li></ul><p>The <strong>Link Appearance</strong> tab contains settings for how your links look and which domains they use.</p><h3 id="link-domains" tabindex="-1">Link domains <a class="header-anchor" href="#link-domains" aria-label="Permalink to &quot;Link domains&quot;">​</a></h3><p>Use custom domains to brand your short links. This section displays your default domain, custom domains, and Branch-provided deep linking domains.</p><h4 id="default-domain" tabindex="-1">Default domain <a class="header-anchor" href="#default-domain" aria-label="Permalink to &quot;Default domain&quot;">​</a></h4><p>The default domain is used for all new links created in your Branch app. To change your default domain:</p><ol><li>Select <strong>Change Default Domain</strong>.</li><li>Select a domain from the <strong>Available Domains</strong> dropdown.</li><li>Select <strong>Save changes</strong>.</li></ol><h4 id="custom-domains" tabindex="-1">Custom domains <a class="header-anchor" href="#custom-domains" aria-label="Permalink to &quot;Custom domains&quot;">​</a></h4><p>You can add custom domains to brand your Branch Links with your own domain name.</p><p>To add a custom domain:</p><ol><li>Select <strong>Add A Custom Domain</strong>.</li><li>Enter your custom domain in the field provided.</li><li>Select <strong>Save Domain</strong>.</li></ol><p>To remove a custom domain, select the delete icon next to the domain you want to remove.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>The ability to add multiple custom domains is only available in some Branch packages.</p></div><h4 id="deep-linking-domains" tabindex="-1">Deep linking domains <a class="header-anchor" href="#deep-linking-domains" aria-label="Permalink to &quot;Deep linking domains&quot;">​</a></h4><p>These are your Branch-provided deep linking domains. Ask your app developer to configure Universal Links and Android App Linking for these domains.</p><p>Branch provides you with a primary deep linking domain and an alternate domain. To change your Branch deep linking subdomain:</p><ol><li>Select <strong>Change Branchbeta.link Domain</strong>.</li><li>Enter your new subdomain in the field provided.</li><li>Select <strong>Confirm Change</strong>.</li></ol><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>Changing a subdomain will result in all links currently using that subdomain not redirecting properly. Make sure to update your mobile app to use the new subdomain after making this change.</p></div><h3 id="link-preview" tabindex="-1">Link preview <a class="header-anchor" href="#link-preview" aria-label="Permalink to &quot;Link preview&quot;">​</a></h3><p>Configure how your link will look by default when shared on social platforms. You can customize this per individual link during link creation.</p><p>To configure the default link preview:</p><ol><li>Select <strong>Configure</strong> in the Link Preview section.</li><li>Enter a <strong>Title</strong> for your link preview.</li><li>Enter a <strong>Description</strong> for your link preview.</li><li>Add a thumbnail image by uploading a file or entering an image URL.</li><li>Select <strong>Save Changes</strong>.</li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>These settings will be used as defaults for new links. You can still customize individual link previews when creating links.</p></div><h3 id="qr-code" tabindex="-1">QR code <a class="header-anchor" href="#qr-code" aria-label="Permalink to &quot;QR code&quot;">​</a></h3><p>Configure your default QR code design. This will apply to all short links created in Branch or via the QR Code API. You can also customize each individual QR code during creation.</p><p>To configure the default QR code design:</p><ol><li><p>Select <strong>Configure</strong> in the QR Code section.</p></li><li><p>Select your styles:</p><ul><li><strong>Choose a pattern</strong> - Select from available QR code pattern styles</li><li><strong>Choose a finder</strong> - Select the style for the corner finder patterns</li><li><strong>Choose a shape</strong> - Select square or circular modules</li><li><strong>Add a border</strong> - Toggle to add a border around your QR code</li></ul></li><li><p>Select your colors:</p><ul><li>Choose from preset colors or enter custom hex values</li><li><strong>Code Color</strong> - The color of the QR code modules</li><li><strong>Finder Color</strong> - The color of the corner finder patterns</li><li><strong>Background Color</strong> - The background color of the QR code</li></ul></li><li><p>Optionally add a logo by uploading a file or entering an image URL.</p></li><li><p>Select <strong>Save Changes</strong>.</p></li></ol>',31)])])}const h=o(t,[["render",r]]);export{g as __pageData,h as default};
